import React, { useState, useEffect } from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Autoplay, Pagination } from 'swiper/modules';

import 'swiper/css';
import 'swiper/css/pagination';
import './MainSlider.css';

function MainSlider() {
  // 1. 현재 화면이 모바일인지 체크하는 상태
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);

  // 2. 화면 크기 변화 감지 (Resize 이벤트)
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const slides = [
    { id: 1, pcImg: 'slider1.jpg', moImg: 'sliderM1.jpg' },
    { id: 2, pcImg: 'slider2.jpg', moImg: 'sliderM2.jpg' },
    { id: 3, pcImg: 'slider3.jpg', moImg: 'sliderM3.jpg' },
    { id: 4, pcImg: 'slider4.jpg', moImg: 'sliderM4.jpg' },
    { id: 5, pcImg: 'slider5.jpg', moImg: 'sliderM5.jpg' },
    { id: 6, pcImg: 'slider6.jpg', moImg: 'sliderM6.jpg' },
    { id: 7, pcImg: 'slider7.jpg', moImg: 'sliderM7.jpg' },
    { id: 8, pcImg: 'slider8.jpg', moImg: 'sliderM8.jpg' },
    { id: 9, pcImg: 'slider9.jpg', moImg: 'sliderM9.jpg' },
  ];

  return (
    <div className="main-slider-wrapper">
      <Swiper
        modules={[Autoplay, Pagination]}
        spaceBetween={0}
        slidesPerView={1}
        loop={true}
        autoplay={{
          delay: 4000,
          disableOnInteraction: false,
        }}
        pagination={{ clickable: true }}
        grabCursor={true}
        className="main-swiper"
      >
        {slides.map((slide) => (
          <SwiperSlide key={slide.id}>
            <div className="main-slide-item">
              <img 
                // isMobile 상태에 따라 파일명 결정
                src={`${process.env.PUBLIC_URL}/img/${isMobile ? slide.moImg : slide.pcImg}`} 
                alt={`슬라이드 ${slide.id}`} 
              />
            </div>
          </SwiperSlide>
        ))}
      </Swiper>
    </div>
  );
}

export default MainSlider;