/* import React from 'react'; */
import '../App.css';
import { useParams } from "react-router-dom";
import { Nav } from 'react-bootstrap'
/* import { useState } from 'react';
import { useEffect } from "react"; */
import React, { useState, useEffect } from 'react';
import { addItem } from '../store.js'
import { useDispatch } from 'react-redux'
import { Button } from 'react-bootstrap'
import { Link } from 'react-router-dom';
import styled from 'styled-components'

const CustomNavWrapper = styled.div`
  margin-top: 80px;
  border-bottom: 2px solid #333; /* 정관장몰 특유의 두꺼운 하단 라인 */

  .nav-tabs {
    border-bottom: none;
    display: flex;
    justify-content: center; /* 탭 중앙 정렬 */
  }

  .nav-item {
    flex: 1; /* 탭 너비 균등 배분 */
    text-align: center;
  }

  .nav-link {
    border: none !important;
    border-radius: 0 !important;
    padding: 20px 0;
    font-size: 16px;
    font-weight: 500;
    color: #999 !important; /* 기본 회색 */
    position: relative;
    transition: all 0.3s;
    background-color: transparent !important;
  }

  /* 활성화된 탭 스타일 (정관장 레드) */
  .nav-link.active {
    color: #881418 !important; 
    font-weight: bold;
  }

  /* 활성화 시 하단 붉은 바 생성 */
  .nav-link.active::after {
    content: '';
    position: absolute;
    bottom: -2px;
    left: 0;
    width: 100%;
    height: 3px;
    background-color: #881418;
  }

  .nav-link:hover {
    color: #881418 !important;
  }
`;

function Detail(props) {
  let { paramId } = useParams();// paramId는 문자열로 오기 때문에 숫자로 바꿔줘야 한다.
  let [tab, setTab] = useState(0);

  // console.log(paramId);

  // const { imgUrl, title, content, price } = props.fruit[paramId];

  // props.fruit 배열에서 id가 paramId와 일치하는 상품을 찾아 item 변수에 저장
  // paramId는 문자열이므로 parseInt를 사용해 숫자로 변환
  // let item = props.fruit.find(f => f.id === parseInt(paramId));

  // const { imgUrl, title, content, price } = item;

  let [fade2, setFade2] = useState('')

  // dispatch 정의 추가
  const dispatch = useDispatch();

  useEffect(() => {
    setFade2('end2')
    return () => {
      setFade2('')
    }
  }, [])

  // 상품 유효성 체크 (이건 Hook 호출 이후에 실행되어야 함)
  let selproduct = props.fruit.find((x) => x.id === Number(paramId));

  // 훅은 조건문(if) 아래에서 호출하면 안 됨 (React가 Hook 순서 기억을 못함)
  if (!selproduct) {
    return <div>해당 상품이 존재하지 않습니다.</div>;
  }

  const { id, imgUrl, title, price, icn1, icn2, detailUrl } = selproduct;

  console.log("내가 선택한 상품은: " + id + " " + title);

  let Banner = styled.div`
  padding : 10px 0;
  height: 300px;
  `;

  let DetailTitle = styled.h2`
  font-weight:bold;
  margin-bottom:20px;
  letter-spacing:3px;
  `;

  let BannerBtn = styled.div`
  color : white;
  font-size:30px;
  width:100%;
  height: 100%;
  padding : 100px 100px;
  background-image: url(${process.env.PUBLIC_URL + "/img/slider2.jpg"});
  background-size:cover;
  background-position:center;
  `;

  return (
    <div className={'container start2 ' + fade2}>

      <Banner>
        <BannerBtn></BannerBtn>
      </Banner>
      <div className="row">
        <div className="col-md-6">
          <img src={process.env.PUBLIC_URL + "/" + imgUrl} width="100%" alt={title} />
        </div>
        <div className="col-md-6" style={{ textAlign: "left", paddingLeft: "50px" }}>
          <h4 className="pt-5">{title}</h4>
          <p style={{ fontSize: "20px", fontWeight: "bold" }}>{price}원</p>
          <p style={{ borderBottom: "1px solid #999", paddingBottom: "30px" }}>혜택 : <img src={process.env.PUBLIC_URL + "/" + icn1} width="15%" alt={title} style={{ margin: "0 10px" }} /><img src={process.env.PUBLIC_URL + "/" + icn2} width="15%" alt={title} /></p>
          <Button
            className='oderBtn'
            onClick={() => {
              //  dispatch(addItem(  {id : 1,  imgurl : 'fruit1.jpg', name : 'Grey Yordan', count : 1}))

              dispatch(
                addItem({
                  id: id,
                  imgurl: imgUrl.replace("img/", ""),
                  name: title,
                  count: 1,
                })
              );

              alert('상품이 추가되었습니다.');
            }}
            style={{ marginRight: "10px" }}
          >
            주문하기
          </Button>

          <Link to="/cart">
            <Button className='oderchkBtn' variant="outline-success"> 주문상품 확인하기 </Button>
          </Link>
          <Link to="#" style={{ marginTop: "50px", display: "block" }}>
            <img
              src={process.env.PUBLIC_URL + "/img/goto.jpg"}
              width="100%"
              alt="정몰 매장 픽업서비스 바로가기"
              style={{ cursor: 'pointer' }}
            />
          </Link>
        </div>
      </div>

      <CustomNavWrapper>
        <Nav variant="tabs" defaultActiveKey="link0">
          <Nav.Item>
            <Nav.Link onClick={() => { setTab(0) }} eventKey="link0">상세페이지</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link onClick={() => { setTab(1) }} eventKey="link1">구매 후기</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link onClick={() => { setTab(2) }} eventKey="link2">판매자 정보</Nav.Link>
          </Nav.Item>
        </Nav>
      </CustomNavWrapper>

      <TabContent tab={tab} detailUrl={detailUrl} />
    </div>
  )
}

function TabContent({ tab, detailUrl }) {
  let [fade, setFade] = useState('');
  useEffect(() => {
    setTimeout(() => { setFade('end') }, 100)
    return () => {
      setFade('')
    }
  }, [tab])

  const reviews = [
    { id: 1, star: "★★★★★", grade: "아주 좋음", date: "2026.02.19", user: "ra****a", title: "아주 좋습니다.", content: "먹기 편하고 건강에 좋습니다." },
    { id: 2, star: "★★★★★", grade: "아주 좋음", date: "2026.02.18", user: "ov************17", title: "배송이 하루만에 와서 좋았어요", content: "설날이라 당연히 몇 일 걸릴 줄 알고 일찍 주문했는데 배송이 하루만에 와서 좋았어요. 덕분에 선물 잘하고 왔습니다~!!" },
    { id: 3, star: "★★★★★", grade: "아주 좋음", date: "2026.02.05", user: "yy****6", title: "아주 좋아요", content: "아주 좋아요" },
  ];

  return (
    <div className={'start ' + fade} style={{ height: '300px' }}>
      {[
        <div><img src={process.env.PUBLIC_URL + "/" + detailUrl} width="100%" /></div>,
        <div style={{ textAlign: 'left', margin: '50px' }}>
          <h5 style={{ fontWeight: 'bold', marginBottom: '20px', color: '#333' }}>일반후기({reviews.length})</h5>

          {reviews.map((review) => (
            <div key={review.id} style={{
              display: 'flex',
              borderTop: '1px solid #eee',
              padding: '25px 0',
              fontSize: '14px'
            }}>
              {/* 왼쪽: 유저 정보 및 별점 */}
              <div style={{ width: '200px', color: '#999' }}>
                <div style={{ marginBottom: '5px' }}>
                  <span style={{ color: '#ffb400', fontSize: '16px', marginRight: '5px' }}>{review.star}</span>
                  <span style={{ color: '#666' }}>{review.grade}</span>
                </div>
                <div style={{ marginBottom: '5px' }}>{review.date}</div>
                <div style={{ marginBottom: '5px' }}>{review.user}</div>
                <div style={{ cursor: 'pointer', fontSize: '12px' }}>신고하기</div>
              </div>

              {/* 오른쪽: 후기 내용 */}
              <div style={{ flex: 1, paddingLeft: '20px' }}>
                <div style={{ fontWeight: 'bold', marginBottom: '10px', color: '#333' }}>{review.title}</div>
                <div style={{ color: '#666', lineHeight: '1.6' }}>{review.content}</div>
              </div>

              {/* 오른쪽 끝: 화살표 아이콘 (간이 구현) */}
              <div style={{ display: 'flex', alignItems: 'center', color: '#ccc' }}>
                <span style={{ transform: 'rotate(-45deg)', borderTop: '2px solid', borderRight: '2px solid', width: '10px', height: '10px', display: 'inline-block' }}></span>
              </div>
            </div>
          ))}
          <div style={{ borderTop: '1px solid #eee' }}></div>
        </div>,
        <div>
          <div style={{
            display: "flex",
            justifyContent: "center",
            gap: "50px",
            textAlign: "left",
            margin: "30px 0",
            padding: "30px 0",
            backgroundColor: "#eaeaea"
          }}>
            <div>
              <p>연락처 : 02-2189-3900</p>
              <p>전자우편 :	cs3900@kgc.co.kr</p>
              <p>교환/반품지명 :	정관장 기본 교환/반품지</p>
            </div>
            <div>
              <p>교환/반품지전화 :	02-2189-3900</p>
              <p>교환/반품지핸드폰 :	02-2189-3900</p>
              <p>교환/반품지주소 :	경기도 이천시 부발읍 황무로 2037-57 2층 한익스 물류 정관장 창고</p>
            </div>
          </div>
          <div className="info-table-container" style={{ textAlign: 'left', fontSize: '14px', color: '#666' }}>
            <table style={{ width: '100%', borderTop: '2px solid #333', borderCollapse: 'collapse' }}>
              <tbody>
                {/* 배송안내 */}
                <tr style={{ borderBottom: '1px solid #eee' }}>
                  <th style={{ width: '20%', padding: '20px', backgroundColor: '#f9f9f9', fontWeight: 'bold', verticalAlign: 'middle' }}>배송안내</th>
                  <td style={{ padding: '20px', lineHeight: '1.8' }}>
                    정관장몰 주문 중 입점사 및 매장(정관장) 배송 제품은 각 해당 판매자(입점사/매장)의 배송정책에 따릅니다.<br />
                    <strong>업체 및 산지에서 택배로 배송 일요일/공휴일 포함 시 추가 배송기일 소요됩니다.</strong><br />
                    <strong>주문제작 상품 및 상품 재고상황, 택배사 사정에 의해 배송 지연 될 수 있습니다.</strong><br />
                    (배송비는 상품상세 상단 배송비 참조)
                    <ol style={{ paddingLeft: '20px', marginTop: '10px' }}>
                      <li>모든 주문은 입금 확인 후 배송준비를 시작합니다.</li>
                      <li>신용카드의 경우는 주문과 동시에 입금확인이 되며 온라인 송금의 경우는 매일 1회 이상에 걸친 담당자의 작업에 의해 입금확인이 됩니다.</li>
                      <li>배송기간은 지역 및 상황에 따라 다르지만 대부분 입금 확인일을 기준으로 1~3일(근무일 기준)안에 배송됩니다.</li>
                      <li>주문하신 상품이 도착할 때, 본인이 아니시더라도 수령하실 분이 꼭 계셔야 합니다.</li>
                    </ol>
                  </td>
                </tr>
                {/* 주문취소안내 */}
                <tr style={{ borderBottom: '1px solid #eee' }}>
                  <th style={{ padding: '20px', backgroundColor: '#f9f9f9', fontWeight: 'bold', verticalAlign: 'middle' }}>주문취소안내</th>
                  <td style={{ padding: '20px', lineHeight: '1.8' }}>
                    <ol style={{ paddingLeft: '20px' }}>
                      <li>주문완료 후 7일 이내에 상품 결제대금을 입금해 주셔야 합니다.</li>
                      <li>가상계좌 결제 신청시 3일 이내에 상품 결제대금을 입금해야 하며, 3일 이후에는 주문내역이 자동 취소됩니다.</li>
                      <li>즉시 주문취소는 배송준비가 이루어지기 전 단계(주문접수)까지 가능합니다.</li>
                      <li>취소하신 결제 방법 중 쿠폰은 반환되지 않습니다.</li>
                    </ol>
                  </td>
                </tr>
                {/* 반품 및 환불 안내 */}
                <tr style={{ borderBottom: '1px solid #eee' }}>
                  <th style={{ padding: '20px', backgroundColor: '#f9f9f9', fontWeight: 'bold', verticalAlign: 'middle' }}>반품 및<br />환불 안내</th>
                  <td style={{ padding: '20px', lineHeight: '1.8' }}>
                    <ol style={{ paddingLeft: '20px' }}>
                      <li>반품의 신청은 주문 오류 또는 단순 변심일 경우 상품 배송완료일로부터 7일 이내 가능합니다.</li>
                      <li>상품이 표시내용과 다르거나 불량일 경우 상품 수령일로부터 3개월 이내 가능합니다.</li>
                      <li>주문하신 상품과 다른 상품이 배송되었거나 파손된 경우 반품처리 후 교환이 가능합니다.</li>
                      <li>상품의 불량/하자 및 표시광고 내용과 다른 경우 배송비는 무료이나, 고객님의 단순변심은 고객님 부담입니다.</li>
                    </ol>
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      ][tab]}
    </div>
  );
}

export default Detail;