import './App.css';
import { Container, Nav, Navbar, Button } from 'react-bootstrap'
import data from './db/pro';
import { useState, useEffect } from 'react';
import TopButton from './components/TopButton'
import Menu from './components/Menu';
import IconMenu from './components/IconMenu';
import MainSlider from './components/MainSlider';
import Products from './components/Products';
import Detail from './components/Detail';
import { Routes, Route, Link, useNavigate, Outlet } from 'react-router-dom'
import Title from './components/Title'
import CommonTitle from './components/CommonTitle'
import Title2 from './components/Title2'
import data2 from "./db/vitamin";
import ComVitamin from "./components/ComVitamin";
import Footer from './components/Footer'
import axios from 'axios'
import Cart from "./components/Cart";
import Board from "./components/Board";
import EventBanner from "./components/Event";
import MessageModal from "./components/Modal";
import EventPage from './components/EventPage';
import ReadyPage from './components/ReadyPage';
import AOS from "aos";
import "aos/dist/aos.css";

function App() {
  let [fruit, setFruit] = useState(data);

  const sortByName = () => {
    let sortedFruit = [...fruit].sort((a, b) => (a.title > b.title ? 1 : -1));
    setFruit(sortedFruit);
    console.log(sortedFruit);
  };

  const sortByPriceLowToHigh = () => {
    let sortedFruit = [...fruit].sort((a, b) => a.price - b.price);
    setFruit(sortedFruit);
    console.log(sortedFruit);
  };

  const sortByPriceHighToLow = () => {
    let sortedFruit = [...fruit].sort((a, b) => b.price - a.price);
    setFruit(sortedFruit);
    console.log(sortedFruit);
  };
  useEffect(() => {
    AOS.init({
      duration: 800,// 전체 지속 시간 (ms)
      delay: 200,// 시작 지연 시간
      offset: 100,// 트리거 위치
      easing: "ease-in-out",
      once: true,// 한 번만 실행
      mirror: false// 스크롤 다시 올릴 때 재실행 여부
    });
  }, []);

  let navigate = useNavigate();

  let [veggie, setVeggie] = useState(data2);

  let [count, setCount] = useState(1); // 더보기 버튼 클릭 횟수

  let [input, setInput] = useState("");



  return (
    <div className="App" style={{ textAlign: "center" }}>
      <>
        <Navbar expand="lg" style={{ backgroundColor: '#902825' }} variant="dark">
          <Container>
            {/* 1. 로고 (왼쪽) */}
            <Navbar.Brand as={Link} to='/'>
              <img src={process.env.PUBLIC_URL + '/img/imgi_1_logo.png'} alt="logo" style={{ width: '100px' }} />
            </Navbar.Brand>

            {/* 2. 모바일용 커스텀 토글 (아이콘 없는 버전) */}
            <Navbar.Toggle
              aria-controls="basic-navbar-nav"
              style={{ border: 'none', color: '#fff', fontSize: '14px' }}
            >
              <span style={{ fontSize: '12px' }}>Quick Menu ▾</span>
            </Navbar.Toggle>

            {/* 3. 메뉴 영역 (Collapse) */}
            <Navbar.Collapse id="basic-navbar-nav">
              {/* me-auto 클래스가 왼쪽 메뉴들을 담고 오른쪽 요소를 밀어냅니다 */}
              <Nav className="me-auto">
                <Nav.Link onClick={() => { navigate('detail/1') }} style={{ color: '#fff' }}>상품페이지</Nav.Link>
                <Nav.Link onClick={() => { navigate('/cart') }} style={{ color: '#fff' }}>장바구니</Nav.Link>
                <Nav.Link onClick={() => { navigate("/board"); }} style={{ color: '#fff' }}> 게시판</Nav.Link>
                <Nav.Link onClick={() => { navigate('/event') }} style={{ color: '#fff' }}>이벤트</Nav.Link>
                <Nav.Link onClick={() => { navigate('/about') }} style={{ color: '#fff' }}>회사소개</Nav.Link>
              </Nav>
            </Navbar.Collapse>

            {/* 4. 오른쪽 고정 영역 (Collapse 외부에 두어 항상 오른쪽에 위치) */}
            <div className="d-flex align-items-center ms-lg-3">
              <MessageModal />
              <Menu />
            </div>

          </Container>
        </Navbar>
        <Routes>{/* 경로에 해당되는 내용 구성 */}
          <Route path="/" element={ // 메인페이지
            <div>
              <MainSlider />
              <IconMenu />
              {/* <Title/> */}
              <CommonTitle title={'정관장 BEST'} subTitle={'부모님부터 아이까지! 남녀노소 맞춤 건강선물'} />
              <div className="container">
                <div className="row">
                  <div className="col-lg-3 col-md-6 mb-2">
                    {/* 검색 추가 */}
                    <input
                      placeholder="상품명을 입력하세요"
                      // 검색어가 변경될 때마다 input 값을 업데이트
                      onChange={(e) => setInput(e.target.value)}
                      value={input}
                      style={{
                        width: "100%",
                        padding: "10px",
                        borderRadius: "4px",
                        border: "1px solid #ccc"
                      }}
                    />

                  </div>
                  <div className="col-lg-3 offset-lg-6 col-md-6 mb-2">
                    {/* select추가 */}
                    <select
                      onChange={(e) => {
                        if (e.target.value === "low") sortByPriceLowToHigh();
                        if (e.target.value === "high") sortByPriceHighToLow();
                        if (e.target.value === "name") sortByName();
                      }}
                      style={{
                        width: "100%",
                        padding: "10px",
                        borderRadius: "4px",
                        border: "1px solid #ccc"
                      }}>
                      <option value="">정렬 선택</option>
                      <option value="low">낮은 가격순</option>
                      <option value="high">높은 가격순</option>
                      <option value="name">이름순</option>
                    </select>
                  </div>
                </div>
              </div>
              <div className="container" style={{ marginTop: "30px" }}>
                <div className="row">
                  {/* 'input'에 맞는 제목을 가진 항목들만 필터링 */}
                  {/* .filter(...)   조건에 맞는 데이터만 걸러냄
                      .map(...)   걸러낸 데이터를 기반으로 컴포넌트를 렌더링 */}
                  {fruit
                    .filter((item) =>
                      item.title.toLowerCase().includes(input.toLowerCase()) // 제목 검색
                    )
                    .map((ele, i) => (
                      <Products fruit={ele} key={ele.id} /> // 필터링된 항목 출력
                    ))}
                </div>
              </div>
              <div className="container">
                <div className="row">
                  <div style={{ textAlign: "center" }}>
                    {/* <Title2 /> */}
                    <CommonTitle title={'가든오브라이프'} subTitle={'전성분 유기농 비타민'} />
                    <div className="container" style={{ marginTop: "30px" }} data-aos="fade-up">
                      <div className="row">
                        {veggie.map((ele, i) => {
                          return <ComVitamin veggie={veggie[i]} key={veggie[i].id} />;
                        })}
                      </div>
                    </div>
                    <Button className='moreBtn' variant="outline-success" count={count} onClick={() => {
                      if (count == 1) {
                        axios.get('https://LGNon.github.io/jungmall/veggie2.json')
                          .then((result) => {
                            let veggie2 = [...veggie, ...result.data];
                            setVeggie(veggie2);
                            setCount(count + 1);
                          })
                          .catch(error => {
                            console.error("Error loading veggie2.json", error);
                          });
                      } else if (count == 2) {
                        axios.get('https://LGNon.github.io/jungmall/veggie3.json')
                          .then((result) => {
                            let veggie3 = [...veggie, ...result.data];
                            setVeggie(veggie3);
                            setCount(count + 1);
                          })
                          .catch(error => {
                            console.error("Error loading veggie3.json", error);
                          });
                      }

                      if (count === 3) {
                        alert("더이상 상품이 없습니다.");
                      }
                    }}> + 3개 상품 더 보기 </Button>{' '}
                  </div>
                </div>
              </div>
              <EventBanner />
              <Footer />
            </div>
          } />
          <Route path="detail/:paramId" element={<Detail fruit={fruit} />} /* 상세페이지 */ />
          <Route path="/event" element={<EventPage />} />
          <Route path="*" element={<ReadyPage />} />
          <Route path="/about" element={<About />} >
            <Route path="member" element={<Member />} />
            <Route path="location" element={<Location />} />
          </Route>
          <Route path="/cart" element={<Cart />} />
          <Route path="/board" element={<Board />} />
        </Routes>
        <TopButton />
      </>
    </div>
  );
}

function About() {
  return (
    <>
      <h4 style={{ display: 'none' }}>회사정보</h4>
      <img
        src={process.env.PUBLIC_URL + "/img/brand1.jpg"}
        width="100%"
        alt="정관장"
        data-aos="fade-up"

      />
      <img
        src={process.env.PUBLIC_URL + "/img/brand2.jpg"}
        width="100%"
        alt="정관장"
        data-aos="fade-up"
      />
      <img
        src={process.env.PUBLIC_URL + "/img/brand3.jpg"}
        width="100%"
        alt="정관장"
        data-aos="fade-up"
      />
      <img
        src={process.env.PUBLIC_URL + "/img/brand4.jpg"}
        width="100%"
        alt="정관장"
        data-aos="fade-up"
      />
      <Outlet></Outlet>
      <Footer />
    </>
  );
}


function Member() {
  return (
    <>
      <h4>Member</h4>
    </>
  );
}


function Location() {
  return (
    <>
      <h4>Location</h4>
    </>
  );
}

export default App;
