import React, { useState } from 'react';
import { Offcanvas, Nav, Accordion } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import '../App.css';

function Menu() {
  const [show, setShow] = useState(false);
  const navigate = useNavigate();

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);

  // 정리된 메뉴 데이터
  const menuData = [
    { title: "홍삼", sub: ["홍삼농축액", "홍삼토닉", "홍삼뿌리", "홍삼한방", "특정기능", "키즈청소년", "여성남성", "건강기호"] },
    { title: "천녹", sub: ["녹용일반", "여성/남성/시니어", "청소년/어린이"] },
    { title: "기다림 침향", sub: [] },
    { title: "GLPro", sub: [] },
    { title: "RXGIN", sub: [] },
    { title: "알파프로젝트", sub: ["포커스 라인", "내추럴 프리미엄 라인"] },
    { title: "화장품", sub: [] },
    { title: "가든오브라이프", sub: [] },
  ];

  return (
    <>
      {/* 햄버거 버튼 */}
      <button className="hamburger-menu" onClick={handleShow} aria-label="메뉴 열기">
        <div className="bar"></div>
        <div className="bar"></div>
        <div className="bar"></div>
      </button>

      <Offcanvas show={show} onHide={handleClose} scroll={true} backdrop={true} className="kgc-offcanvas" placement="end">
        <Offcanvas.Header closeButton>
          <Offcanvas.Title className="kgc-menu-title">카테고리</Offcanvas.Title>
        </Offcanvas.Header>
        <Offcanvas.Body>
          <Accordion flush>
            {menuData.map((menu, i) => (
              <Accordion.Item eventKey={i.toString()} key={i}>
                {menu.sub.length > 0 ? (
                  <>
                    <Accordion.Header>{menu.title}</Accordion.Header>
                    <Accordion.Body>
                      <Nav className="flex-column">
                        {menu.sub.map((sub, j) => (
                          <Nav.Link key={j} onClick={() => { navigate('/shop'); handleClose(); }}>
                            {sub}
                          </Nav.Link>
                        ))}
                      </Nav>
                    </Accordion.Body>
                  </>
                ) : (
                  <div className="accordion-direct-link" onClick={() => { navigate('/shop'); handleClose(); }}>
                    {menu.title}
                  </div>
                )}
              </Accordion.Item>
            ))}
          </Accordion>
        </Offcanvas.Body>
      </Offcanvas>
    </>
  );
}

export default Menu;