import React, { useState } from 'react';
import '../App.css';
import { Button, Table, Form, Alert } from 'react-bootstrap';

const FruitBoard = () => {
    // 게시물 목록 상태
    const [boardList, setBoardList] = useState([
        { no: "1", title: '비회원으로 배송조회 가능한가요?', description: '비회원으로 상품을 시켰는데 배송조회를 하고싶어요.', viewCount: 1 },
        { no: "2", title: '설연휴 배송 관련 문의', description: '이번에 설 선물로 선물세트를 샀는데 설 전에 배송되나요?. ', viewCount: 2 },
        { no: "3", title: '반품시 상품은 어디로 보내나요?', description: '반품을 하고싶은데 상품을 어디에 놔두면 되나요?', viewCount: 1 },
        { no: "4", title: '모바일에서 로그인이 안돼요', description: 'pc로는 로그인이 되는데 모바일앱에서는 로그인이 안돼요.', viewCount: 1 }
    ]);

    // UI 상태
    const [listOk, setListOk] = useState(true);
    const [readOk, setReadOk] = useState(false);
    const [writeOk, setWriteOk] = useState(false);
    const [editOk, setEditOk] = useState(false);
    const [boardInfo, setBoardInfo] = useState({});
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [editNo, setEditNo] = useState(null);
    const [editTitle, setEditTitle] = useState('');
    const [editDescription, setEditDescription] = useState('');
    const [errorMessage, setErrorMessage] = useState('');

    // --- 정관장 프리미엄 스타일 정의 ---
    const styles = {
        mainTitle: {
            fontSize: "26px",
            fontWeight: "700",
            color: "#222",
            textAlign: "center",
            marginBottom: "40px",
            letterSpacing: "-1px"
        },
        redPoint: { color: "#a6192e" },
        tableHeader: {
            backgroundColor: "#f8f8f8",
            borderTop: "2px solid #333",
            fontSize: "15px",
            color: "#444"
        },
        listTitle: {
            cursor: 'pointer',
            textAlign: 'left',
            fontWeight: "500",
            color: "#333"
        },
        actionBtn: {
            fontSize: "12px",
            padding: "4px 10px",
            borderRadius: "0",
            marginLeft: "5px"
        },
        writeBtn: {
            backgroundColor: "#a6192e",
            border: "none",
            borderRadius: "0",
            padding: "10px 25px",
            fontSize: "15px"
        },
        formLabel: {
            fontSize: "16px",
            fontWeight: "600",
            marginBottom: "10px",
            display: "block"
        },
        inputField: {
            borderRadius: "0",
            padding: "12px",
            borderColor: "#ddd"
        }
    };

    // 로직 함수들 (기능은 동일 유지)
    const boardListView = () => { setReadOk(false); setWriteOk(false); setEditOk(false); setListOk(true); };
    const boardRead = (no) => {
        setListOk(false); setWriteOk(false); setEditOk(false); setReadOk(true);
        const updatedList = boardList.map(b => b.no === no ? { ...b, viewCount: b.viewCount + 1 } : b);
        setBoardList(updatedList);
        const selectedBoard = boardList.find(b => b.no === no);
        setBoardInfo(selectedBoard);
    };
    const boardWrite = () => { setListOk(false); setWriteOk(true); };
    const boardSave = () => {
        if (title.trim() === '' || description.trim() === '') {
            setErrorMessage('제목과 내용을 모두 입력해주세요!');
            return;
        }
        const newBoard = { no: (boardList.length + 1).toString(), title, description, viewCount: 0 };
        setBoardList([...boardList, newBoard]);
        setTitle(''); setDescription(''); setErrorMessage('');
        boardListView();
    };
    const boardDelete = (no) => {
        const updatedList = boardList.filter(b => b.no !== no.toString());
        setBoardList(updatedList);
        boardListView();
    };
    const boardEdit = (no) => {
        setEditOk(true); setListOk(false);
        const boardToEdit = boardList.find(b => b.no === no);
        setEditNo(boardToEdit.no); setEditTitle(boardToEdit.title); setEditDescription(boardToEdit.description);
    };
    const updateBoard = () => {
        const updatedBoardList = boardList.map(b => b.no === editNo ? { ...b, title: editTitle, description: editDescription } : b);
        setBoardList(updatedBoardList);
        boardListView();
    };

    return (
        <div className="container" style={{ marginTop: "80px", maxWidth: "1000px" }}>
            <h3 style={styles.mainTitle}>정관장몰 <span style={styles.redPoint}>고객문의</span> 게시판</h3>

            {/* 1. 게시글 목록 */}
            {listOk && (
                <div style={{ marginTop: "30px" }}>
                    <Table hover responsive style={{ borderBottom: "1px solid #ddd" }}>
                        <thead style={styles.tableHeader}>
                            <tr className="text-center">
                                <th style={{ width: "10%" }}>번호</th>
                                <th style={{ width: "50%" }}>제목</th>
                                <th style={{ width: "15%" }}>조회수</th>
                                <th style={{ width: "25%" }}>관리</th>
                            </tr>
                        </thead>
                        <tbody>
                            {boardList.slice().reverse().map(board => (
                                <tr key={board.no} className="text-center">
                                    <td style={{ verticalAlign: "middle" }}>{board.no}</td>
                                    <td style={{ ...styles.listTitle, verticalAlign: "middle" }} onClick={() => boardRead(board.no)}>
                                        {board.title}
                                    </td>
                                    <td style={{ verticalAlign: "middle" }}>{board.viewCount}</td>
                                    <td style={{ verticalAlign: "middle" }}>
                                        <Button variant="outline-dark" style={styles.actionBtn} onClick={() => boardEdit(board.no)}>수정</Button>
                                        <Button variant="outline-danger" style={styles.actionBtn} onClick={() => boardDelete(board.no)}>삭제</Button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </Table>
                    <div style={{ textAlign: "right", marginTop: "20px" }}>
                        <Button style={styles.writeBtn} onClick={boardWrite}>문의글 작성하기</Button>
                    </div>
                </div>
            )}

            {/* 2. 게시글 읽기 */}
            {readOk && (
                <div style={{ borderTop: "2px solid #333", borderBottom: "1px solid #ddd", padding: "40px 20px" }}>
                    <h4 style={{ fontWeight: "700", marginBottom: "20px" }}>{boardInfo.title}</h4>
                    <div style={{ fontSize: "14px", color: "#888", marginBottom: "30px" }}>
                        조회수: {boardInfo.viewCount}
                    </div>
                    <p style={{ minHeight: "200px", lineHeight: "1.8", color: "#444" }}>{boardInfo.description}</p>
                    <div style={{ textAlign: "center", marginTop: "40px" }}>
                        <Button variant="dark" style={{ borderRadius: "0", padding: "10px 40px" }} onClick={boardListView}>목록으로</Button>
                    </div>
                </div>
            )}

            {/* 3. 게시글 작성 */}
            {writeOk && (
                <div style={{ borderTop: "2px solid #a6192e", padding: "40px", backgroundColor: "#fafafa" }}>
                    <h5 style={{ fontWeight: "700", marginBottom: "30px" }}>문의글 남기기</h5>
                    {errorMessage && <Alert variant="danger">{errorMessage}</Alert>}
                    <Form.Group className="mb-4">
                        <label style={styles.formLabel}>제목</label>
                        <Form.Control 
                            style={styles.inputField} 
                            type="text" 
                            value={title} 
                            onChange={(e) => setTitle(e.target.value)} 
                            placeholder="제목을 입력해주세요." 
                        />
                    </Form.Group>
                    <Form.Group className="mb-4">
                        <label style={styles.formLabel}>문의 내용</label>
                        <Form.Control 
                            as="textarea" 
                            rows={8} 
                            style={styles.inputField} 
                            value={description} 
                            onChange={(e) => setDescription(e.target.value)} 
                            placeholder="문의 내용을 상세히 작성해 주세요." 
                        />
                    </Form.Group>
                    <div style={{ textAlign: "center" }}>
                        <Button variant="secondary" style={{ borderRadius: "0", marginRight: "10px" }} onClick={boardListView}>취소</Button>
                        <Button style={styles.writeBtn} onClick={boardSave}>등록하기</Button>
                    </div>
                </div>
            )}

            {/* 4. 게시글 수정 */}
            {editOk && (
                <div style={{ borderTop: "2px solid #333", padding: "40px", backgroundColor: "#fff" }}>
                    <h5 style={{ fontWeight: "700", marginBottom: "30px" }}>게시물 수정</h5>
                    <Form.Group className="mb-4">
                        <Form.Control 
                            style={styles.inputField} 
                            type="text" 
                            value={editTitle} 
                            onChange={(e) => setEditTitle(e.target.value)} 
                        />
                    </Form.Group>
                    <Form.Group className="mb-4">
                        <Form.Control 
                            as="textarea" 
                            rows={8} 
                            style={styles.inputField} 
                            value={editDescription} 
                            onChange={(e) => setEditDescription(e.target.value)} 
                        />
                    </Form.Group>
                    <div style={{ textAlign: "center" }}>
                        <Button variant="outline-dark" style={{ borderRadius: "0", marginRight: "10px" }} onClick={boardListView}>목록</Button>
                        <Button variant="dark" style={{ borderRadius: "0" }} onClick={updateBoard}>수정완료</Button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default FruitBoard;