import React, { useState } from 'react';
import { Button, Modal, Form } from 'react-bootstrap';
import '../App.css';

function MessageModal() {
  const [show, setShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);

  return (
    <>
      {/* 트리거 버튼: 네비바나 페이지 내 어디든 배치 가능 */}
      <Button className="btn-kgc" onClick={handleShow}>
        문의하기
      </Button>

      {/* 정관장 테마 모달 */}
      <Modal show={show} onHide={handleClose} centered className="kgc-modal">
        <Modal.Header closeButton>
          <Modal.Title>1:1 문의하기</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <Form>
            <Form.Group className="mb-3">
              <Form.Label>성함</Form.Label>
              <Form.Control type="text" placeholder="이름을 입력하세요" />
            </Form.Group>
            <Form.Group className="mb-3">
              <Form.Label>문의내용</Form.Label>
              <Form.Control as="textarea" rows={4} placeholder="내용을 입력해주세요" />
            </Form.Group>
          </Form>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={handleClose}>
            취소
          </Button>
          <Button className="btn-kgc-submit" onClick={handleClose}>
            전송하기
          </Button>
        </Modal.Footer>
      </Modal>
    </>
  );
}

export default MessageModal;