import "../App.css"
import { Table, Button } from "react-bootstrap";
import { useDispatch, useSelector } from "react-redux";
import { addCount, decreaseCount, deleteItem, sortName } from "../store.js";
import { Link } from "react-router-dom";

function Cart() {
  const { user: { name }, cart } = useSelector((state) => state);
  let dispatch = useDispatch();

  // --- 정관장 스타일 커스텀 CSS ---
  const styles = {
    container: { padding: "60px 0", maxWidth: "1000px" },
    title: { 
      fontSize: "28px", 
      fontWeight: "700", 
      color: "#222", 
      marginBottom: "40px",
      borderBottom: "2px solid #a6192e", // 정관장 메인 레드 컬러
      paddingBottom: "15px",
      display: "inline-block"
    },
    tableHeader: {
      borderTop: "2px solid #333",
      borderBottom: "1px solid #ddd",
      backgroundColor: "#f9f9f9",
      fontSize: "15px",
      fontWeight: "600"
    },
    productImg: {
      width: "90px",
      height: "90px",
      objectFit: "cover",
      borderRadius: "4px",
      border: "1px solid #eee"
    },
    productName: {
      fontSize: "16px",
      fontWeight: "500",
      color: "#333",
      textDecoration: "none"
    },
    countBadge: {
      display: "inline-flex",
      alignItems: "center",
      border: "1px solid #ddd",
      borderRadius: "4px",
      overflow: "hidden"
    },
    countBtn: {
      backgroundColor: "#fff",
      border: "none",
      color: "#333",
      padding: "5px 12px",
      fontSize: "18px",
      lineHeight: "1"
    },
    countNum: {
      padding: "0 15px",
      borderLeft: "1px solid #ddd",
      borderRight: "1px solid #ddd",
      fontWeight: "600"
    },
    mainRedBtn: {
      backgroundColor: "#a6192e", // 정관장 공식 레드
      border: "none",
      padding: "10px 25px",
      borderRadius: "0", // 각진 디자인이 더 고급스러움
      fontWeight: "500"
    },
    deleteBtn: {
      fontSize: "13px",
      color: "#888",
      textDecoration: "underline",
      background: "none",
      border: "none"
    },
    verticalMiddle: { verticalAlign: "middle" }
  };

  return (
    <div className="container" style={styles.container}>
      <div className="row">
        <div className="col-sm-12 text-center">
          
          <h2 style={styles.title}>{name}님의 장바구니</h2>

          <Table hover responsive style={{ marginTop: "20px" }}>
            <thead style={styles.tableHeader}>
              <tr>
                <th style={{ width: "15%" }}>상품</th>
                <th style={{ width: "40%" }}>상품정보</th>
                <th style={{ width: "20%" }}>수량</th>
                <th style={{ width: "25%" }}>선택</th>
              </tr>
            </thead>
            <tbody>
              {cart.map(({ id, imgurl, name, count }, i) => (
                <tr key={i} style={{ borderBottom: "1px solid #eee" }}>
                  {/* 상품 이미지 */}
                  <td style={styles.verticalMiddle}>
                    <Link to={`/detail/${id}`}>
                      <img 
                        src={process.env.PUBLIC_URL + `/img/${imgurl}`} 
                        style={styles.productImg} 
                        alt={name}
                      />
                    </Link>
                  </td>
                  
                  {/* 상품명 */}
                  <td style={{ ...styles.verticalMiddle, textAlign: "left" }}>
                    <Link to={`/detail/${id}`} style={styles.productName}>
                      {name}
                    </Link>
                  </td>

                  {/* 수량 변경 컨트롤러 */}
                  <td style={styles.verticalMiddle}>
                    <div style={styles.countBadge}>
                      <button style={styles.countBtn} onClick={() => dispatch(decreaseCount(id))}>-</button>
                      <span style={styles.countNum}>{count}</span>
                      <button style={styles.countBtn} onClick={() => dispatch(addCount(id))}>+</button>
                    </div>
                  </td>

                  {/* 삭제 버튼 */}
                  <td style={styles.verticalMiddle}>
                    <button 
                      style={styles.deleteBtn}
                      onClick={() => dispatch(deleteItem(id))}
                    >
                      상품삭제
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>

          {/* 하단 버튼 영역 */}
          <div style={{ marginTop: "40px", display: "flex", justifyContent: "center", gap: "10px" }}>
            <Button 
              variant="outline-secondary" 
              style={{ borderRadius: "0", padding: "10px 25px" }}
              onClick={() => dispatch(sortName())}
            >
              이름순 정렬
            </Button>
            <Button 
              style={styles.mainRedBtn}
            >
              전체 상품 주문하기
            </Button>
          </div>

        </div>
      </div>
    </div>
  );
}

export default Cart;