import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Autoplay, Pagination, Navigation } from 'swiper/modules';

// Swiper 스타일 import (필수)
import 'swiper/css';
import 'swiper/css/pagination';
import 'swiper/css/navigation';
import '../App.css';

function EventBanner() {
  // 배너 데이터 배열
  const banners = [
    { id: 1, img: 'img/event1.jpg', link: '#' },
    { id: 2, img: 'img/event2.jpg', link: '#' },
  ];

  return (
    <div className="banner-container" style={{ marginTop: '30px' }}>
      <Swiper
        spaceBetween={0}
        centeredSlides={true}
        autoplay={{
          delay: 3000, // 3초마다 전환
          disableOnInteraction: false,
        }}
        pagination={{
          clickable: true,
        }}
        navigation={true}
        modules={[Autoplay, Pagination, Navigation]}
        loop={true} // 무한 루프
        className="mySwiper"
      >
        {banners.map((item) => (
          <SwiperSlide key={item.id}>
            <a href={item.link}>
              <img
                src={process.env.PUBLIC_URL + "/" + item.img}
                alt={`이벤트 배너 ${item.id}`}
                style={{ width: '100%', display: 'block' }}
              />
            </a>
          </SwiperSlide>
        ))}
      </Swiper>
    </div>
  );
}

export default EventBanner;