import React from 'react';
import { Container, Row, Col } from 'react-bootstrap';
import './EventPage.css';

function EventPage() {
  // 이벤트 데이터 배열 (이미지 이름 규칙 적용)
  const eventList = [
    { id: 1, title: "[리뷰이벤트] 내가 산 홍삼을 소개합니다!", sub: "제품 리뷰하고 해시태그 다시면 추첨을 통해 경품을 드려요!", date: "2026-01-23 ~ 2026-03-15" },
    { id: 2, title: "신학기 메시지 카드 보내기", sub: "지금 메시지 카드로 마음을 전해보세요!", date: "2026-02-19 ~ 2026-03-31" },
    { id: 3, title: "[정관장] 한눈에 보는 정몰 혜택", sub: "웰컴 혜택 모음!", date: "2026-02-19 ~ 2026-12-31" },
    { id: 4, title: "신상품 출시 이벤트", sub: "농축액 전용 스푼 출시 이벤트", date: "2025-03-06 ~ 2029-12-31" },
  ];

  return (
    <Container className="event-page-container" style={{ marginTop: '50px', marginBottom: '80px' }}>
      <h3 style={{ fontWeight: 'bold', marginBottom: '30px', textAlign: 'left' }}>이벤트</h3>
      
      <Row>
        {eventList.map((event) => (
          <Col lg={6} md={6} sm={12} key={event.id} className="mb-5">
            <div className="event-card">
              {/* 이미지 경로: /public/img/eventBanner(번호).jpg */}
              <div className="event-img-box">
                <img 
                  src={process.env.PUBLIC_URL + "/img/" + `eventBanner${event.id}.webp`} 
                  alt={event.title} 
                  className="event-img"
                />
              </div>
              <div className="event-txt-box" style={{ textAlign: 'left', marginTop: '15px' }}>
                <p className="event-title" style={{ fontSize: '14px', color: '#666', marginBottom: '5px' }}>{event.title}</p>
                <h5 className="event-sub-title" style={{ fontWeight: 'bold', marginBottom: '10px' }}>{event.sub}</h5>
                <p className="event-date" style={{ fontSize: '13px', color: '#999' }}>
                  <i className="bi bi-clock" style={{ marginRight: '5px' }}></i> {event.date}
                </p>
              </div>
            </div>
          </Col>
        ))}
      </Row>

      {/* 하단 페이지네이션 (간이 구현) */}
      <div className="pagination-box" style={{ marginTop: '30px', borderTop: '1px solid #eee', paddingTop: '20px' }}>
        <span style={{ borderBottom: '2px solid #333', padding: '0 5px', fontWeight: 'bold' }}>1</span>
      </div>
    </Container>
  );
}

export default EventPage;