import React from 'react';
import { Container, Row, Col } from 'react-bootstrap';
import { Link } from 'react-router-dom'; // Link 임포트

function IconMenu() {
  const menuList = [
    { id: 1, name: "뿌리삼담임" },
    { id: 2, name: "천녹" },
    { id: 3, name: "기다림" },
    { id: 4, name: "황진단" },
    { id: 5, name: "아이키커" },
    { id: 6, name: "메시지 카드" },
    { id: 7, name: "선물포장" },
    { id: 8, name: "매장재고조회" },
  ];

  return (
    <Container style={{ marginTop: '40px', marginBottom: '40px' }}>
      <Row className="justify-content-center text-center">
        {menuList.map((item) => (
          <Col key={item.id} xs={3} md={1} className="mb-4" style={{ minWidth: '100px' }}>
            {/* ReadyPage로 연결되는 링크 */}
            <Link to="/ready" style={{ textDecoration: 'none', color: 'inherit' }}>
              <div style={{ cursor: 'pointer' }}>
                <img
                  src={`${process.env.PUBLIC_URL}/img/icn${item.id}.jpg`}
                  alt={item.name}
                  style={{
                    width: '60px',
                    height: '60px',
                    borderRadius: '15px',
                    backgroundColor: '#f8f8f8',
                    objectFit: 'contain',
                    marginBottom: '10px'
                  }}
                />
                <p style={{ fontSize: '13px', fontWeight: '500', color: '#333' }}>
                  {item.name}
                </p>
              </div>
            </Link>
          </Col>
        ))}
      </Row>
    </Container>
  );
}

export default IconMenu;