import React, { useState, useEffect } from 'react';

/**
 * TopButton 컴포넌트
 * 모든 페이지에서 공통으로 사용되며, 스크롤 위치에 따라 나타납니다.
 */
const TopButton = () => {
  const [showButton, setShowButton] = useState(false);

  // 1. 스크롤 감지 로직
  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 400) {
        setShowButton(true);
      } else {
        setShowButton(false);
      }
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  // 2. 최상단 이동 함수
  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: "smooth" // 부드러운 이동 효과
    });
  };

  // 3. 인라인 스타일 (CSS 파일 수정 없이 적용)
  const style = {
    position: 'fixed',
    bottom: '50px',
    right: '50px',
    width: '55px',
    height: '55px',
    borderRadius: '50%',
    backgroundColor: '#902825', // 정관장 브랜드 레드
    color: '#ffffff',
    border: 'none',
    boxShadow: '0 4px 10px rgba(0,0,0,0.3)',
    cursor: 'pointer',
    display: showButton ? 'flex' : 'none', // 400px 이상일 때만 노출
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: '9999', // 다른 요소보다 항상 위에 위치
    transition: 'opacity 0.3s ease-in-out',
    fontSize: '24px',
    fontWeight: 'bold'
  };

  return (
    <button
      style={style}
      onClick={scrollToTop}
      title="맨 위로 이동"
      onMouseOver={(e) => e.currentTarget.style.backgroundColor = '#7a1f1d'}
      onMouseOut={(e) => e.currentTarget.style.backgroundColor = '#902825'}
    >
      ↑
    </button>
  );
};

export default TopButton;