import React from 'react';
import { Button, Container } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import Footer from './Footer'; // 기존 Footer 활용

function ReadyPage() {
  const navigate = useNavigate();

  return (
    <div className="ready-page-wrapper">
      <Container style={{ minHeight: '80vh', display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', padding: '100px 0' }}>

        {/* 아이콘 섹션 (AOS 효과 적용) */}
        <div data-aos="zoom-in" style={{ fontSize: '100px', marginBottom: '20px', color: '#902825' }}>
          <i className="bi bi-clock-history"></i>
        </div>

        {/* 메인 텍스트 */}
        <h2 data-aos="fade-up" style={{ fontWeight: 'bold', color: '#333', fontSize: '36px', letterSpacing: '-1px' }}>
          페이지 <span style={{ color: '#902825' }}>준비 중</span>입니다.
        </h2>

        {/* 서브 텍스트 */}
        <p data-aos="fade-up" data-aos-delay="200" style={{ color: '#666', marginTop: '20px', fontSize: '18px', lineHeight: '1.6', textAlign: 'center' }}>
          고객님께 더 나은 품질의 서비스를 제공하기 위해<br />
          현재 정성껏 페이지를 제작하고 있습니다. 조만간 멋진 모습으로 찾아뵙겠습니다.
        </p>

        {/* 버튼 섹션 */}
        <div data-aos="fade-up" data-aos-delay="400" style={{ marginTop: '40px' }}>
          <Button
            className="btn-kgc-ready"
            onClick={() => navigate('/')}
          >
            홈으로 돌아가기
          </Button>
          <Button
            variant="outline-secondary"
            onClick={() => navigate(-1)}
            style={{ marginLeft: '10px', padding: '12px 35px', borderRadius: '4px' }}
          >
            이전 페이지
          </Button>
        </div>
      </Container>

      <Footer />
    </div>
  );
}

export default ReadyPage;