import React from "react";
import { useNavigate } from "react-router-dom";
import { Nav } from "react-bootstrap";

const Products = (props) => {
  const { id, title, price, imgUrl, content, icn1, icn2 } = props.fruit;
  let navigate = useNavigate();
  return (
    <div className="col-md-4" style={{ marginBottom: "50px" }} data-aos="fade-up">
      <Nav.Link onClick={() => { navigate("/detail/" + id) }} className="m_Hover">
        <img src={process.env.PUBLIC_URL + "/" + imgUrl} width="80%" />
        <h5 style={{ margin: "10px auto", width: "80%" }}>{title}</h5>
        <span style={{ fontSize: "20px" }}>{price}원</span>
        <p style={{ marginTop: "10px" }}><img src={process.env.PUBLIC_URL + "/" + icn1} width="20%" /><img src={process.env.PUBLIC_URL + "/" + icn2} width="20%" /></p>
      </Nav.Link>
    </div>
  );
};

export default Products;